/*
You are given a string s and an array of strings words. All the strings of words are of the same length.

A concatenated string is a string that exactly contains all the strings of any permutation of words concatenated.

    For example, if words = ["ab","cd","ef"], then "abcdef", "abefcd", "cdabef", "cdefab", "efabcd", and "efcdab" are all concatenated strings. "acdbef" is not a concatenated string because it is not the concatenation of any permutation of words.

Return an array of the starting indices of all the concatenated substrings in s. You can return the answer in any order.

Example 1:

Input: s = "barfoothefoobarman", words = ["foo","bar"]

Output: [0,9]

Explanation:

The substring starting at 0 is "barfoo". It is the concatenation of ["bar","foo"] which is a permutation of words.
The substring starting at 9 is "foobar". It is the concatenation of ["foo","bar"] which is a permutation of words.

Example 2:

Input: s = "wordgoodgoodgoodbestword", words = ["word","good","best","word"]

Output: []

Explanation:

There is no concatenated substring.

Example 3:

Input: s = "barfoofoobarthefoobarman", words = ["bar","foo","the"]

Output: [6,9,12]

Explanation:

The substring starting at 6 is "foobarthe". It is the concatenation of ["foo","bar","the"].
The substring starting at 9 is "barthefoo". It is the concatenation of ["bar","the","foo"].
The substring starting at 12 is "thefoobar". It is the concatenation of ["the","foo","bar"].

Constraints:

    1 <= s.length <= 10000
    1 <= words.length <= 5000
    1 <= words[i].length <= 30
    s and words[i] consist of lowercase English letters.

 */
#include <bits/stdc++.h>
using namespace std;

void printStrings(vector<string> arr) {
    for (int i=0; i<arr.size(); i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
}

void printVector(vector<int> &arr) {
    for (int i=0; i<arr.size(); i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
}

void printVector(vector<bool> &arr) {
    for (int i=0; i<arr.size(); i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
}

bool isDictEqual(unordered_map<string, int> &dict1, unordered_map<string, int> &dict2) {
    unordered_map<string, int>::iterator itr1 = dict1.begin();
    if (dict1.size() != dict2.size()) {
        // cout << "Size not equal" << endl;
        return false;
    }

    while (itr1 != dict1.end()) {
        string key = itr1 -> first;
        if (dict1[key] != dict2[key]) {
            return false;
        }
        itr1++;
    }

    return true;
}

vector<int> findSubstring(string s, vector<string>& words) {
    vector<int> result = {};

    // Create our dictionary first
    unordered_map<string, int> dict;
    for (int i=0; i<words.size(); i++) {
        if (dict.find(words[i]) == dict.end()) {
            dict.insert({words[i], 1});
        } else {
            int currentVal = dict[words[i]];
            dict[words[i]] = currentVal + 1;
        }
    }

    // cout << "Is Present Vector: " << endl;

    int wordsSize = words.size();
    int patternSize = words[0].size();

    bool singleValue = false;
    if (patternSize == 1 && dict.size() == 1) {
        singleValue = true;
    }

    int windowSize = wordsSize * patternSize;
    // cout << "Window Size: " << windowSize << endl;

    vector<string> currentWords;
    string currentWindow = "";
    int leftIndex = 0;
    int i=0;
    while (i < s.size() ) {
        currentWindow.push_back(s[i]);

        if (currentWindow.size() == windowSize) {
            // cout << "Current Window: " << currentWindow << endl;

            int j = 0;
            string currentPattern = "";
            bool found = true;
            unordered_map<string, int> tempDict;
            while (j < windowSize) {
                currentPattern.push_back(currentWindow[j]);
                if (currentPattern.size() == patternSize) {
                    // cout << "Current Pattern: " << currentPattern << endl;
                    if (dict.find(currentPattern) == dict.end()) {
                        // cout << "Current Pattern not found in dict" << endl;
                        found = false;
                        tempDict.clear();
                        break;
                    }

                    // cout << "Pattern found in dict" << endl;
                    if (tempDict.find(currentPattern) == tempDict.end()) {
                        tempDict.insert({currentPattern, 1});
                    } else {
                        int currentVal = tempDict[currentPattern];
                        tempDict[currentPattern] = currentVal + 1;
                    }
                    currentPattern = "";
                }
                j++;
            }

            // cout << "Value of found: " << found << endl;
            bool equalDict = isDictEqual(dict, tempDict);
            if (found && equalDict) {
                result.push_back(leftIndex);
            }

            // check if current window will be equal
            while (i < s.size() && singleValue) {
                // cout << "Value will be equal: " << endl;
                // value of currentWindow will be same after erase
                i++;
                leftIndex++;
                if (i < s.size() && found && equalDict) {
                    result.push_back(leftIndex);
                }
            }

            currentWindow.erase(0, 1);
            leftIndex++;
        }
        i++;
    }

    return result;
}

